/**
 * SMS notification adapter.
 *
 * Implements the NotificationAdapter interface for the 'sms' channel.
 * Formats notification payloads as text messages and sends them via
 * a configurable transport.
 *
 * NOTE: The user preferences model (src/models/user-preferences.ts) was
 * designed with an email-only assumption. It only contains `EmailPreferences`
 * and the `PreferencesService.shouldSendEmail()` method. To fully support
 * SMS notifications, the preferences model needs to be extended with
 * SMS-specific preferences (enabled, phone number, category subscriptions).
 * See COORDINATION.md for details on what needs to change.
 */

import type { NotificationAdapter, NotificationResult } from './notification.adapter.js';
import type { NotificationChannel, NotificationPayload } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/** Configuration for the SMS adapter. */
export interface SmsConfig {
  /** The sender phone number or short code (e.g., "+15551234567"). */
  fromNumber: string;
  /** Optional API key for the SMS provider. */
  apiKey?: string;
}

/** Default SMS configuration. */
export const defaultSmsConfig: SmsConfig = {
  fromNumber: '+15550000000',
};

/** Record of an SMS that was sent. */
export interface SentSms {
  to: string;
  from: string;
  body: string;
  sentAt: Date;
}

/**
 * Transport interface for sending SMS messages.
 * Allows swapping between real SMS providers and test/in-memory transports.
 */
export interface SmsTransport {
  sendMessage(options: {
    from: string;
    to: string;
    body: string;
  }): Promise<{ messageId: string }>;
}

/**
 * In-memory SMS transport for testing and development.
 * Stores all sent messages and allows inspection.
 */
export class InMemorySmsTransport implements SmsTransport {
  private messages: SentSms[] = [];

  async sendMessage(options: {
    from: string;
    to: string;
    body: string;
  }): Promise<{ messageId: string }> {
    const sms: SentSms = {
      to: options.to,
      from: options.from,
      body: options.body,
      sentAt: new Date(),
    };
    this.messages.push(sms);
    return { messageId: `sms-${this.messages.length}` };
  }

  getMessages(): SentSms[] {
    return [...this.messages];
  }

  clear(): void {
    this.messages = [];
  }
}

/** Simple phone number validation — checks for E.164 format. */
function isValidPhoneNumber(phone: string): boolean {
  return /^\+[1-9]\d{6,14}$/.test(phone);
}

/**
 * Format a notification payload into a concise SMS body.
 * SMS messages have a 160-character limit for single segments,
 * so we keep the message compact.
 */
function formatSmsBody(payload: NotificationPayload): string {
  return `${payload.subject}\n${payload.body}`;
}

export class SmsAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'sms';
  private logger = new Logger('SmsAdapter');
  private config: SmsConfig;
  private transport: SmsTransport;

  constructor(config?: Partial<SmsConfig>, transport?: SmsTransport) {
    this.config = { ...defaultSmsConfig, ...config };
    this.transport = transport ?? new InMemorySmsTransport();
  }

  /**
   * Send an SMS notification.
   * Validates the recipient phone number, formats the message, and sends via transport.
   * Never throws — returns a failed NotificationResult on error.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      // Validate recipient phone number
      const recipient = payload.recipient.trim();
      if (!isValidPhoneNumber(recipient)) {
        const error = `Invalid or missing phone number: ${payload.recipient}`;
        this.logger.error(error);
        return { success: false, error };
      }

      // Format SMS body
      const body = formatSmsBody(payload);

      // Send via transport
      this.logger.info(`Sending SMS to ${recipient}`);
      const result = await this.transport.sendMessage({
        from: this.config.fromNumber,
        to: recipient,
        body,
      });

      this.logger.info(`SMS sent successfully: ${result.messageId}`);
      return {
        success: true,
        externalId: result.messageId,
      };
    } catch (err: unknown) {
      const error = err instanceof Error ? err.message : 'Unknown SMS send error';
      this.logger.error(`Failed to send SMS: ${error}`);
      return { success: false, error };
    }
  }

  /**
   * Get the underlying transport (useful for testing with InMemorySmsTransport).
   */
  getTransport(): SmsTransport {
    return this.transport;
  }

  /**
   * Get all sent SMS messages. Only works if using InMemorySmsTransport.
   */
  getSentMessages(): SentSms[] {
    if (this.transport instanceof InMemorySmsTransport) {
      return this.transport.getMessages();
    }
    return [];
  }

  /**
   * Clear sent SMS messages. Only works if using InMemorySmsTransport.
   */
  clearSentMessages(): void {
    if (this.transport instanceof InMemorySmsTransport) {
      this.transport.clear();
    }
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import {
  SmsAdapter,
  InMemorySmsTransport,
  defaultSmsConfig,
} from '../../src/adapters/sms.adapter.js';
import type { SmsTransport } from '../../src/adapters/sms.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    recipient: '+15551234567',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    channel: 'sms',
    type: 'order_confirmation',
    priority: 'normal',
    ...overrides,
  };
}

describe('SmsAdapter', () => {
  let adapter: SmsAdapter;
  let transport: InMemorySmsTransport;

  beforeEach(() => {
    transport = new InMemorySmsTransport();
    adapter = new SmsAdapter({ fromNumber: '+15559999999' }, transport);
  });

  it('should have channel set to sms', () => {
    expect(adapter.channel).toBe('sms');
  });

  describe('send', () => {
    it('should send an SMS and return success', async () => {
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.externalId).toBeDefined();
      expect(result.externalId).toMatch(/^sms-/);
    });

    it('should deliver message to the transport', async () => {
      await adapter.send(makePayload());

      const messages = transport.getMessages();
      expect(messages).toHaveLength(1);
      expect(messages[0]?.to).toBe('+15551234567');
      expect(messages[0]?.from).toBe('+15559999999');
      expect(messages[0]?.body).toContain('Order Confirmation');
      expect(messages[0]?.body).toContain('Your order has been placed');
    });

    it('should format body with subject and body text', async () => {
      await adapter.send(makePayload({
        subject: 'Test Subject',
        body: 'Test body content',
      }));

      const messages = transport.getMessages();
      expect(messages[0]?.body).toBe('Test Subject\nTest body content');
    });

    it('should trim recipient phone number', async () => {
      await adapter.send(makePayload({ recipient: '  +15551234567  ' }));

      const messages = transport.getMessages();
      expect(messages).toHaveLength(1);
      expect(messages[0]?.to).toBe('+15551234567');
    });
  });

  describe('recipient validation', () => {
    it('should reject empty phone number', async () => {
      const result = await adapter.send(makePayload({ recipient: '' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid or missing phone number');
    });

    it('should reject phone number without + prefix', async () => {
      const result = await adapter.send(makePayload({ recipient: '15551234567' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid or missing phone number');
    });

    it('should reject phone number with letters', async () => {
      const result = await adapter.send(makePayload({ recipient: '+1555abc4567' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid or missing phone number');
    });

    it('should reject phone number that is too short', async () => {
      const result = await adapter.send(makePayload({ recipient: '+12345' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid or missing phone number');
    });

    it('should reject phone number starting with +0', async () => {
      const result = await adapter.send(makePayload({ recipient: '+05551234567' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid or missing phone number');
    });

    it('should accept valid international numbers', async () => {
      const result = await adapter.send(makePayload({ recipient: '+447911123456' }));

      expect(result.success).toBe(true);
    });
  });

  describe('transport errors', () => {
    it('should handle Error throws from transport', async () => {
      const failingTransport: SmsTransport = {
        sendMessage: async () => { throw new Error('Provider timeout'); },
      };
      const failAdapter = new SmsAdapter({}, failingTransport);

      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('Provider timeout');
    });

    it('should handle non-Error throws from transport', async () => {
      const failingTransport: SmsTransport = {
        sendMessage: async () => { throw 'network failure'; },
      };
      const failAdapter = new SmsAdapter({}, failingTransport);

      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('Unknown SMS send error');
    });
  });

  describe('getSentMessages', () => {
    it('should return sent messages when using InMemorySmsTransport', async () => {
      await adapter.send(makePayload());
      await adapter.send(makePayload({ recipient: '+15559876543' }));

      const messages = adapter.getSentMessages();
      expect(messages).toHaveLength(2);
    });

    it('should return empty array when using non-InMemory transport', () => {
      const customTransport: SmsTransport = {
        sendMessage: async () => ({ messageId: 'ext-1' }),
      };
      const customAdapter = new SmsAdapter({}, customTransport);

      expect(customAdapter.getSentMessages()).toEqual([]);
    });
  });

  describe('clearSentMessages', () => {
    it('should clear sent messages when using InMemorySmsTransport', async () => {
      await adapter.send(makePayload());
      expect(adapter.getSentMessages()).toHaveLength(1);

      adapter.clearSentMessages();
      expect(adapter.getSentMessages()).toHaveLength(0);
    });

    it('should not throw when using non-InMemory transport', () => {
      const customTransport: SmsTransport = {
        sendMessage: async () => ({ messageId: 'ext-1' }),
      };
      const customAdapter = new SmsAdapter({}, customTransport);

      expect(() => customAdapter.clearSentMessages()).not.toThrow();
    });
  });

  describe('getTransport', () => {
    it('should return the underlying transport', () => {
      expect(adapter.getTransport()).toBe(transport);
    });
  });

  describe('defaultSmsConfig', () => {
    it('should have a default fromNumber', () => {
      expect(defaultSmsConfig.fromNumber).toBe('+15550000000');
    });
  });

  describe('InMemorySmsTransport', () => {
    it('should store messages and return incrementing IDs', async () => {
      const t = new InMemorySmsTransport();

      const r1 = await t.sendMessage({ from: '+1', to: '+2', body: 'a' });
      const r2 = await t.sendMessage({ from: '+1', to: '+3', body: 'b' });

      expect(r1.messageId).toBe('sms-1');
      expect(r2.messageId).toBe('sms-2');
      expect(t.getMessages()).toHaveLength(2);
    });

    it('should clear all messages', async () => {
      const t = new InMemorySmsTransport();
      await t.sendMessage({ from: '+1', to: '+2', body: 'a' });

      t.clear();
      expect(t.getMessages()).toHaveLength(0);
    });
  });

  describe('integration with NotificationService', () => {
    it('should be registrable as an adapter', async () => {
      // Verify the adapter satisfies the NotificationAdapter interface
      // by checking the required properties and methods
      expect(adapter.channel).toBe('sms');
      expect(typeof adapter.send).toBe('function');

      // Verify it works end-to-end
      const result = await adapter.send(makePayload());
      expect(result.success).toBe(true);

      const messages = adapter.getSentMessages();
      expect(messages).toHaveLength(1);
    });
  });
});

